package store

import (
	"context"
	"os"
	"sync"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

var (
	instance     Store
	instanceInit sync.Once
	instanceErr  error
)

type Config struct {
	StoreType            string
	RedisAddr            string
	RedisPassword        string
	RedisPasswordRequired bool
	ValkeyAddr           string
	ValkeyPassword       string
	ValkeyPasswordRequired bool
	ValkeyDisableCache   bool
	ValkeyForceSingle    bool
}

func getConfig() *Config {
	cfg := &Config{
		StoreType:            getEnv("STORE_TYPE", "redis"),
		RedisAddr:            getEnv("REDIS_ADDR", ""),
		RedisPassword:        getEnv("REDIS_PASSWORD", ""),
		RedisPasswordRequired: getEnvBool("REDIS_PASSWORD_REQUIRED", true),
		ValkeyAddr:           getEnv("VALKEY_ADDR", ""),
		ValkeyPassword:       getEnv("VALKEY_PASSWORD", ""),
		ValkeyPasswordRequired: getEnvBool("VALKEY_PASSWORD_REQUIRED", true),
		ValkeyDisableCache:   getEnvBool("VALKEY_DISABLE_CACHE", false),
		ValkeyForceSingle:    getEnvBool("VALKEY_FORCE_SINGLE", false),
	}
	return cfg
}

func getEnv(key, defaultValue string) string {
	if value, ok := os.LookupEnv(key); ok {
		return value
	}
	return defaultValue
}

func getEnvBool(key string, defaultValue bool) bool {
	if value, ok := os.LookupEnv(key); ok {
		return value == "true" || value == "1"
	}
	return defaultValue
}

func Storage() (Store, error) {
	instanceInit.Do(func() {
		cfg := getConfig()
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		switch cfg.StoreType {
		case "valkey":
			instance, instanceErr = NewValkeyStore(ctx, cfg)
		case "redis":
			fallthrough
		default:
			instance, instanceErr = NewRedisStore(ctx, cfg)
		}
	})
	return instance, instanceErr
}

func NewRedisStore(ctx context.Context, cfg *Config) (Store, error) {
	if cfg.RedisAddr == "" {
		return nil, ErrNotFound
	}
	if cfg.RedisPasswordRequired && cfg.RedisPassword == "" {
		return nil, ErrNotFound
	}
	store := &redisStore{
		addr:    cfg.RedisAddr,
		password: cfg.RedisPassword,
	}
	if err := store.Ping(ctx); err != nil {
		return nil, err
	}
	return store, nil
}

func NewValkeyStore(ctx context.Context, cfg *Config) (Store, error) {
	if cfg.ValkeyAddr == "" {
		return nil, ErrNotFound
	}
	if cfg.ValkeyPasswordRequired && cfg.ValkeyPassword == "" {
		return nil, ErrNotFound
	}
	store := &valkeyStore{
		addr:          cfg.ValkeyAddr,
		password:      cfg.ValkeyPassword,
		disableCache:  cfg.ValkeyDisableCache,
		forceSingle:  cfg.ValkeyForceSingle,
	}
	if err := store.Ping(ctx); err != nil {
		return nil, err
	}
	return store, nil
}

func StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	s, err := Storage()
	if err != nil {
		return err
	}
	return s.StoreSandbox(ctx, sandbox)
}

func GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	s, err := Storage()
	if err != nil {
		return nil, err
	}
	return s.GetSandboxBySessionID(ctx, sessionID)
}

func UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	s, err := Storage()
	if err != nil {
		return err
	}
	return s.UpdateSandbox(ctx, sandbox)
}

func DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	s, err := Storage()
	if err != nil {
		return err
	}
	return s.DeleteSandboxBySessionID(ctx, sessionID)
}

func ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	s, err := Storage()
	if err != nil {
		return nil, err
	}
	return s.ListExpiredSandboxes(ctx, before, limit)
}

func ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	s, err := Storage()
	if err != nil {
		return nil, err
	}
	return s.ListInactiveSandboxes(ctx, before, limit)
}

func UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	s, err := Storage()
	if err != nil {
		return err
	}
	return s.UpdateSessionLastActivity(ctx, sessionID, at)
}
